def indices_accuracy(ground_truth):
    import pandas as pd
    output = pd.read_csv('indices_greater_than_50.csv')
    indices = output['index'].tolist()
    elements = output['element'].tolist()

    # Expecting ground_truth to be a dictionary {index: element}
    for idx in indices:
        if idx not in ground_truth or ground_truth[idx] != elements[indices.index(idx)]:
            return False
    return True

