def image_quality_evaluation(ground_truth):
    from skimage import io
    import numpy as np

    ground_truth_images = [io.imread(os.path.join("profile_images1/", img)) for img in ground_truth]
    processed_images = [io.imread(os.path.join("processed_images/", f'processed_image_{index}.jpg')) for index, img in enumerate(ground_truth)]

    quality_scores = []
    for gt_img, proc_img in zip(ground_truth_images, processed_images):
        score = np.mean(gt_img == proc_img)  # Simple comparison; this may vary based on quality metric
        quality_scores.append(score)

    return np.mean(quality_scores)

