def z_score_standardization(ground_truth):
    import pandas as pd
    output = pd.read_csv("X_sub_norm.csv")
    means = output.mean()
    stds = output.std()
    return all(abs(mean) < 1e-5 for mean in means) and all(abs(std - 1) < 1e-5 for std in stds)

