def thresholding_range_validation(ground_truth):
    import numpy as np
    thresholded_data = np.load("thresholded_data.np")

    # Check if all values are within the range [0, 255]
    return np.all((thresholded_data >= 0) & (thresholded_data <= 255))

Function3:
def mask_integrity_check(ground_truth):
    import numpy as np
    masked_data = np.load("masked_data.np")

    # Check if all values outside the mask are set to 170
    mask = np.logical_or(masked_data == 170, masked_data != 170)
    return np.all(mask)

